            frequency[num] = (frequency[num] || 0) + 1;
        }

        let candidates = [];
        for (const num in frequency) {
            if (frequency[num] >= threshold) {
                candidates.push(parseInt(num));
            }
        }

        if (candidates.length === 0) {
